// Driver code
#include <iostream>
#include <vector>
#include <stack>

class Solution {
public:
    bool solve(std::vector<int>& nums, int n) {
        std::stack<int> s;
        for (int i = 0; i < n; ++i) {
            s.push(nums[i]);
            if (i < n - 1 && nums[i] == nums[i + 1]) return true;
            if (s.size() > 1 && s.top() == nums[i]) return true;
        }
        return false;
    }
};

int main() {
    Solution s;
    std::vector<int> nums = {1, 2, 3, 2, 4, 5};
    int n = nums.size();
    if (s.solve(nums, n)) std::cout << 'Duplicate found'
    else std::cout << 'No duplicate found'
    return 0;
